"use strict";(self.webpackChunkdocs_site=self.webpackChunkdocs_site||[]).push([["6842"],{6491(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/fr/docs/intro","label":"Pr\xe9sentation des produits","docId":"intro","unlisted":false},{"type":"category","label":"D\xe9marrage rapide","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/fr/docs/getting-started/quick-start","label":"D\xe9ploiement rapide","docId":"getting-started/quick-start","unlisted":false},{"type":"link","href":"/fr/docs/getting-started/first-run","label":"Premi\xe8re mise en service","docId":"getting-started/first-run","unlisted":false}]},{"type":"category","label":"D\xe9ploiement","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/fr/docs/deployment/docker-compose","label":"D\xe9ploiement de production de Docker Compose","docId":"deployment/docker-compose","unlisted":false},{"type":"link","href":"/fr/docs/deployment/reverse-proxy","label":"Proxy inverse et HTTPS","docId":"deployment/reverse-proxy","unlisted":false},{"type":"link","href":"/fr/docs/deployment/cloudflare","label":"Configuration de Cloudflare","docId":"deployment/cloudflare","unlisted":false},{"type":"link","href":"/fr/docs/deployment/sandbox","label":"D\xe9ploiement du code bac \xe0 sable","docId":"deployment/sandbox","unlisted":false},{"type":"link","href":"/fr/docs/deployment/sqlite-mode","label":"D\xe9ploiement l\xe9ger (SQLite)","docId":"deployment/sqlite-mode","unlisted":false}]},{"type":"category","label":"R\xe9f\xe9rence de configuration","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/fr/docs/configuration/env-core","label":"Variables environnementales cl\xe9s","docId":"configuration/env-core","unlisted":false},{"type":"link","href":"/fr/docs/configuration/env-advanced","label":"Variable environnementale optimale","docId":"configuration/env-advanced","unlisted":false}]},{"type":"category","label":"Guide d\'utilisation","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/fr/docs/guide/chat","label":"Conversation et mod\xe8le","docId":"guide/chat","unlisted":false},{"type":"link","href":"/fr/docs/guide/deep-research","label":"Recherche profonde","docId":"guide/deep-research","unlisted":false},{"type":"link","href":"/fr/docs/guide/python-sandbox","label":"Python bac \xe0 sable","docId":"guide/python-sandbox","unlisted":false},{"type":"link","href":"/fr/docs/guide/knowledge-bases","label":"Base de connaissances et documentation","docId":"guide/knowledge-bases","unlisted":false},{"type":"link","href":"/fr/docs/guide/files","label":"Documents et espace de stockage","docId":"guide/files","unlisted":false},{"type":"link","href":"/fr/docs/guide/images","label":"Images g\xe9n\xe9r\xe9es","docId":"guide/images","unlisted":false},{"type":"link","href":"/fr/docs/guide/workspaces","label":"Espace de travail d\u2019\xe9quipe","docId":"guide/workspaces","unlisted":false},{"type":"link","href":"/fr/docs/guide/sharing-and-data","label":"Partage et donn\xe9es","docId":"guide/sharing-and-data","unlisted":false},{"type":"link","href":"/fr/docs/guide/account","label":"Compte et s\xe9curit\xe9","docId":"guide/account","unlisted":false}]},{"type":"category","label":"Console d\'administration","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/fr/docs/admin/overview","label":"Vue d\'ensemble de l\'arri\xe8re","docId":"admin/overview","unlisted":false},{"type":"link","href":"/fr/docs/admin/channels-models","label":"Canal et mod\xe8le","docId":"admin/channels-models","unlisted":false},{"type":"link","href":"/fr/docs/admin/users-quotas","label":"Utilisateurs, quotas et cr\xe9dits","docId":"admin/users-quotas","unlisted":false},{"type":"link","href":"/fr/docs/admin/site-settings","label":"Configuration du site et mod\xe9ration","docId":"admin/site-settings","unlisted":false},{"type":"link","href":"/fr/docs/admin/backup-migration","label":"Sauvegarde et migration","docId":"admin/backup-migration","unlisted":false},{"type":"link","href":"/fr/docs/admin/analytics","label":"Quantit\xe9 et analyse","docId":"admin/analytics","unlisted":false},{"type":"link","href":"/fr/docs/admin/files","label":"Liste des documents","docId":"admin/files","unlisted":false}]},{"type":"link","href":"/fr/docs/faq","label":"Questions fr\xe9quentes","docId":"faq","unlisted":false}]},"docs":{"admin/analytics":{"id":"admin/analytics","title":"Quantit\xe9 et analyse","description":"Il y a deux points de vue dans le menu \xab Donn\xe9es \xbb pour voir le m\xeame classeur chaque ligne d\'appel du mod\xe8le sous-jacent est not\xe9e, pas seulement les r\xe9ponses de chat visibles par l\'utilisateur, la g\xe9n\xe9ration de titres, le routage de requ\xeate, le r\xe9sum\xe9 de compression, l\'extraction de m\xe9moire, l\'emballage, les images, l\'examen, la planification et la v\xe9rification de Deep Research, etc. Les appels internes sont \xe9galement not\xe9s (ils g\xe9n\xe8rent \xe9galement des co\xfbts, devraient \xeatre pris en compte dans le co\xfbt de l\'utilisateur).","sidebar":"tutorialSidebar"},"admin/backup-migration":{"id":"admin/backup-migration","title":"Sauvegarde et migration","description":"Syst\xe8me de sauvegarde et migration (/admin/backup L\'exportation et le t\xe9l\xe9chargement de sauvegardes compl\xe8tes, la restauration de l\'importation de biblioth\xe8ques compl\xe8tes, l\'exportation / l\'importation de configurations de site l\xe9g\xe8res et l\'inspection et la reconstruction de la biblioth\xe8que vectorielle Qdrant. La sauvegarde compl\xe8te est un fichier logique neutre du moteur, le m\xeame zip peut \xeatre import\xe9 entre SQLite et les d\xe9ploiements PostgreSQL, la migration transversale, la migration transversale, la r\xe9cup\xe9ration des catastrophes sont tous sur cette voie, sans avoir \xe0 toucher pg_dump ou des documents de base de donn\xe9es.","sidebar":"tutorialSidebar"},"admin/channels-models":{"id":"admin/channels-models","title":"Canal et mod\xe8le","description":"Mod\xe8le d\u2019acc\xe8s \xe0 deux niveaux : Le canal (Channel)\xab Qu\u2019est-ce qu\u2019un accord, quel accord ? \xbbLe mod\xe8le (Model) Sous le canal, le tuyau \xab quel mod\xe8le sp\xe9cifique, quelle capacit\xe9, comment le prix \xbb. les deux niveaux sont maintenus en arri\xe8re-plan, stockent la base de donn\xe9es, modifient la distribution de code z\xe9ro et entrent en vigueur apr\xe8s la conservation.","sidebar":"tutorialSidebar"},"admin/files":{"id":"admin/files","title":"Liste des documents","description":"\xab Donn\xe9es > Fichiers \xbb est une vue unifi\xe9e des fichiers t\xe9l\xe9charg\xe9s sur l\u2019ensemble du site : tous les fichiers t\xe9l\xe9charg\xe9s par les utilisateurs dans conversation et base de connaissances, un tableau complet et un nettoyage. Convient pour l\u2019audit de stockage, le nettoyage de grands fichiers occupant de l\u2019espace, l\u2019examen des infractions.","sidebar":"tutorialSidebar"},"admin/overview":{"id":"admin/overview","title":"Vue d\'ensemble de l\'arri\xe8re","description":"La plupart des configurations op\xe9rationnelles d\'Aivory sont effectu\xe9es dans la console d\'administration : amont canal et mod\xe8le, utilisateur et quota, cr\xe9dits et code d\'\xe9change, mod\xe9ration, migration de sauvegarde, rapports d\'utilisation, etc., tous stock\xe9s dans la base de donn\xe9es, qui s\'appliquent aux demandes ult\xe9rieures et ne n\xe9cessitent pas de red\xe9marrage.","sidebar":"tutorialSidebar"},"admin/site-settings":{"id":"admin/site-settings","title":"Configuration du site et mod\xe9ration","description":"Cette page couvre les configurations op\xe9rationnelles de la console d\'administration : chaque commutateur de la page de configuration globale, ainsi que les annonces, les modes de connexion, les comp\xe9tences, les transcriptions vocales, les limites de t\xe9l\xe9chargement, bac \xe0 sable, les configurations de niveau site r\xe9cup\xe9r\xe9es sur chaque page d\'\xe9tiquette, et enfin le syst\xe8me de mod\xe9ration. Tous les param\xe8tres sont conserv\xe9s dans la base de donn\xe9es settings Dans le tableau, apr\xe8s avoir cliqu\xe9 sur \xab Enregistrer \xbb, les demandes ult\xe9rieures sont imm\xe9diatement valables, sans red\xe9marrer le conteneur.","sidebar":"tutorialSidebar"},"admin/users-quotas":{"id":"admin/users-quotas","title":"Utilisateurs, quotas et cr\xe9dits","description":"Cette page couvre les trois pages de la cat\xe9gorie \xab Utilisateur \xbb : Utilisateur (/admin/users Le groupe d\u2019utilisateurs (/admin/user-groups Code de l\u2019\xe9change (/admin/redeem-codes Le mod\xe8le quota, le syst\xe8me de cr\xe9dits et les limites quotidiennes associ\xe9s.","sidebar":"tutorialSidebar"},"configuration/env-advanced":{"id":"configuration/env-advanced","title":"Variable environnementale optimale","description":"\u9AD8\u7EA7\u8C03\u4F18\u73AF\u5883\u53D8\u91CF}","sidebar":"tutorialSidebar"},"configuration/env-core":{"id":"configuration/env-core","title":"Variables environnementales cl\xe9s","description":"Cette page d\xe9crit les variables environnementales qui modifient r\xe9ellement le d\xe9ploiement et l\'exploitation quotidienne du service : surveillance de service, base de donn\xe9es, cl\xe9s, limites, liaison de services externes, composition de couches et bac \xe0 sable sidecar. Les param\xe8tres de contr\xf4le du comportement interne du syst\xe8me (parall\xe8lement, r\xe9essai, taille de lot, lecture du rythme du cycle, etc.) ne sont pas disponibles sur cette page, voir Variable environnementale optimale\u3002","sidebar":"tutorialSidebar"},"deployment/cloudflare":{"id":"deployment/cloudflare","title":"Configuration de Cloudflare","description":"En accrochant Aivory \xe0 Cloudflare, vous pouvez obtenir trois choses \xe0 la fois : Station de source cach\xe9e IP (Les visiteurs ne voient que les adresses des n\u0153uds de bord de Cloudflare) Certificat de bord gratuit et renouvelable automatiquement (Vous n\'avez pas \xe0 vous soucier du HTTPS du navigateur vers Cloudflare) et de Cloudflare DDoS et WAF de base Les avantages associ\xe9s incluent le cache \xe0 bord de ressources statiques et d\'acc\xe8s proche Anycast \xe0 l\'\xe9chelle mondiale.","sidebar":"tutorialSidebar"},"deployment/docker-compose":{"id":"deployment/docker-compose","title":"D\xe9ploiement de production de Docker Compose","description":"Cette page d\xe9crit en profondeur le document compose de production d\'Aivory deploy/docker-compose.prod.yml: Responsabilit\xe9 de chaque service avec des contr\xf4les de sant\xe9, des volumes de donn\xe9es et des strat\xe9gies de sauvegarde, des images miroirs pr\xe9-construites et des changements locaux, une planification des ressources, des commandes d\'exploitation quotidiennes, des processus de mise \xe0 niveau et un tableau de suivi des pannes courantes. Si vous voulez simplement tirer le service le plus rapidement possible, consultez d\'abord D\xe9ploiement rapide Cette page suppose que vous avez termin\xe9 le d\xe9ploiement initial.","sidebar":"tutorialSidebar"},"deployment/reverse-proxy":{"id":"deployment/reverse-proxy","title":"Proxy inverse et HTTPS","description":"Avec Aivory app Le conteneur est 8787 L\u2019acc\xe8s au spa \xe0 l\u2019avant et /api L\'arri\xe8re-plan ne parle que d\'HTTP. L\'environnement de production sugg\xe8re d\'y placer une couche de proxy inverse responsable de la r\xe9siliation du TLS. Cette page fournit les deux configurations compl\xe8tes de Nginx et Caddy qui peuvent \xeatre coll\xe9es directement et explique pourquoi chacune d\'entre elles est ainsi \xe9crite.","sidebar":"tutorialSidebar"},"deployment/sandbox":{"id":"deployment/sandbox","title":"D\xe9ploiement du code bac \xe0 sable","description":"La capacit\xe9 d\'ex\xe9cution de code Python d\'Aivory est fournie par un service bac \xe0 sable ind\xe9pendant. Cette page d\xe9crit l\'architecture sidecar, la signification de chaque configuration cl\xe9 dans composer, les limites de s\xe9curit\xe9 et la fa\xe7on de d\xe9ployer bac \xe0 sable ind\xe9pendamment sur une autre machine. Python bac \xe0 sable\u3002","sidebar":"tutorialSidebar"},"deployment/sqlite-mode":{"id":"deployment/sqlite-mode","title":"D\xe9ploiement l\xe9ger (SQLite)","description":"L\'arri\xe8re de l\'Aivory est automatiquement s\xe9lectionn\xe9 en fonction des variables environnementales lors du d\xe9marrage// Pour commencer, utilisez PostgreSQL, sinon, par exemple. .db Utilisation de SQLite int\xe9gr\xe9 ; REDISURL La mise en place d\u2019un cache ou d\u2019une cohorte dans le processus ; QDRANT_URL Le vide est d\xe9sactiv\xe9 pour la r\xe9cup\xe9ration vectorielle, le RAG revient pour injecter l\'int\xe9gralit\xe9 du texte. La production et le d\xe9veloppement du binaire sont les m\xeames, les pilotes SQLite ont \xe9t\xe9 compil\xe9s dans l\'image miroir.","sidebar":"tutorialSidebar"},"faq":{"id":"faq","title":"Questions fr\xe9quentes","description":"Cette page r\xe9sume les questions les plus fr\xe9quentes concernant le d\xe9ploiement et l\'utilisation quotidienne. Chaque r\xe9ponse est accompagn\xe9e d\'un lien vers la page du manuel correspondant, pour plus de d\xe9tails, rendez-vous sur la page correspondante.","sidebar":"tutorialSidebar"},"getting-started/first-run":{"id":"getting-started/first-run","title":"Premi\xe8re mise en service","description":"selon D\xe9ploiement rapide Une fois le conteneur tir\xe9, il n\u2019y a pas d\u2019utilisateur, de canal et de mod\xe8le dans le syst\xe8me. Cette page suit l\u2019ordre de la configuration compl\xe8te du \xab syst\xe8me vide \xbb \xe0 \xab envoyer le premier message \xbb : cr\xe9er un administrateur, ajouter un canal amont, cr\xe9er un mod\xe8le, d\xe9finir le mod\xe8le par d\xe9faut et le mod\xe8le de t\xe2che, configurer le mod\xe8le d\u2019embedding, et enfin quelques am\xe9liorations optionnelles.","sidebar":"tutorialSidebar"},"getting-started/quick-start":{"id":"getting-started/quick-start","title":"D\xe9ploiement rapide","description":"Cette page vous permet d\'utiliser Docker Compose pour tirer en 5 minutes une pile compl\xe8te d\'Aivory : PostgreSQL, Redis, Qdrant, code int\xe9gr\xe9 bac \xe0 sable, et un SPA front-end de serveur simultan\xe9. /api Derri\xe8re le app Containers (les deux provenant de la m\xeame source, sans nom de domaine ni configuration CORS).","sidebar":"tutorialSidebar"},"guide/account":{"id":"guide/account","title":"Compte et s\xe9curit\xe9","description":"Cette page couvre l\u2019ensemble du cycle de vie des comptes d\u2019Aivory : enregistrement (codes d\u2019authentification de bo\xeete aux lettres, v\xe9rification de verrouillage), connexion, v\xe9rification en deux \xe9tapes (2FA), connexion \xe0 la source d\u2019identit\xe9 de tiers, gestion de mots de passe et d\u2019image, appareils de connexion, suppression de compte, param\xe8tres d\u2019apparence, langue d\u2019interface et installation de PWA.","sidebar":"tutorialSidebar"},"guide/chat":{"id":"guide/chat","title":"Conversation et mod\xe8le","description":"Cette page pr\xe9sente aux utilisateurs finaux, un par un, chaque \xe9l\xe9ment et chaque op\xe9ration de l\'interface de conversation Aivory : nouvelle conversation, s\xe9lecteur de mod\xe8le, capacit\xe9 compl\xe8te de la bo\xeete d\'entr\xe9e, flux de sortie et de processus de r\xe9flexion, ligne d\'appel d\'outils, op\xe9rations de messagerie, arbre de branche, gestion de conversation, interrogations de grammaire et raccourcis.","sidebar":"tutorialSidebar"},"guide/deep-research":{"id":"guide/deep-research","title":"Recherche profonde","description":"Deep Research (Research en profondeur) est une ligne de recherche ind\xe9pendante et multi-roule : le mod\xe8le \xe9labore d\'abord un plan de recherche, effectue des recherches et des lectures de plusieurs pages sur le Web, v\xe9rifie les affirmations et g\xe9n\xe8re finalement une copie. Rapport complet avec r\xe9f\xe9rence \xe0 la source Son budget d\'outils est consid\xe9rablement am\xe9lior\xe9 par rapport aux r\xe9ponses aux questions ordinaires et convient aux questions de synth\xe8se qui n\xe9cessitent des preuves de sources multiples.","sidebar":"tutorialSidebar"},"guide/files":{"id":"guide/files","title":"Documents et espace de stockage","description":"La page \xab Documents \xbb est une entr\xe9e de gestion unique pour tout le contenu que vous t\xe9l\xe9chargez : barre lat\xe9rale, cliquez sur \xab Documents \xbb en dessous de \xab Dessin \xbb. Les pi\xe8ces jointes de conversation et les documents de la base de connaissances sont r\xe9pertori\xe9s sur cette page \u2013 vous n\u2019avez plus besoin de chercher une par une dans chaque conversation ou base de connaissances.","sidebar":"tutorialSidebar"},"guide/images":{"id":"guide/images","title":"Images g\xe9n\xe9r\xe9es","description":"Aivory ne cr\xe9e pas de \xab page de dessin \xbb isol\xe9e, mais s\u2019int\xe8gre \xe0 la profondeur de la conversation : en s\xe9lectionnant un mod\xe8le d\u2019image dans la m\xeame bo\xeete de conversation, vous pouvez dessiner, en retirant le mod\xe8le de conversation, et continuer \xe0 traiter cette image avec Python bac \xe0 sable. Cette page couvre les entr\xe9es de dessin, l\u2019optimisation des styles et des conseils, l\u2019\xe9dition de la carte de r\xe9f\xe9rence, les limites et les cr\xe9dits de facturation, la galerie personnelle et la biblioth\xe8que pour chaque utilisateur du c\xf4t\xe9 administrateur.","sidebar":"tutorialSidebar"},"guide/knowledge-bases":{"id":"guide/knowledge-bases","title":"Base de connaissances et documentation","description":"base de connaissances est un entrep\xf4t de documents \xe0 long terme d\'Aivory : un ensemble de documents est t\xe9l\xe9charg\xe9 une seule fois, puis chaque conversation peut le charger en r\xe9ponse \xe0 une question de recherche, et les r\xe9ponses apportent automatiquement des r\xe9f\xe9rences \xe0 la source. Cette page couvre la cr\xe9ation de base de connaissances, la biblioth\xe8que de documents, l\'utilisation de la conversation, les principes de recherche et la liste compl\xe8te des r\xe9sultats de recherche.","sidebar":"tutorialSidebar"},"guide/python-sandbox":{"id":"guide/python-sandbox","title":"Python bac \xe0 sable","description":"Chaque conversation est dot\xe9e d\'un conteneur Python bac \xe0 sable ind\xe9pendant. Mod\xe8le peut \xe9crire et ex\xe9cuter le code Python de mani\xe8re autonome pendant la r\xe9ponse: analyser les donn\xe9es que vous avez t\xe9l\xe9charg\xe9es, dessiner des graphiques, traiter des tables, et m\xeame g\xe9n\xe9rer des documents PDF / PPTX / DOCX / XLSX t\xe9l\xe9chargeables. bac \xe0 sable fonctionne en parall\xe8le avec la conversation et conserve les fichiers tout au long du cycle de vie de la conversation.","sidebar":"tutorialSidebar"},"guide/sharing-and-data":{"id":"guide/sharing-and-data","title":"Partage et donn\xe9es","description":"Cette page pr\xe9sente toutes les fonctionnalit\xe9s d\u2019Aivory li\xe9es \xe0 vos donn\xe9es : partage de conversations en tant que liens publics, exportation de donn\xe9es personnelles, importation de l\u2019historique de conversations \xe0 partir d\u2019autres plateformes ou du site, page de param\xe8tres de confidentialit\xe9 et activation et gestion de la m\xe9moire de conversations.","sidebar":"tutorialSidebar"},"guide/workspaces":{"id":"guide/workspaces","title":"Espace de travail d\u2019\xe9quipe","description":"espace de travail (Workspace) est l\'unit\xe9 de collaboration multi-personnel d\'Aivory: un Totalement ind\xe9pendant Un espace partag\xe9 o\xf9 les conversations, les projets et la base de connaissances sont visibles pour tous les membres, o\xf9 les conversations peuvent \xeatre poursuivies par n\'importe quel membre et o\xf9 les frais sont enregistr\xe9s sur la personne qui envoie le message. Cette page couvre les relations entre l\'espace personnel et l\'espace d\'\xe9quipe, la cr\xe9ation et l\'invitation \xe0 rejoindre, la visibilit\xe9 du contenu partag\xe9, les autorisations des membres, le changement d\'espace et l\'archivage de la conversation.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Pr\xe9sentation des produits","description":"Aivory est une plate-forme de conversation multi-mod\xe8les AI open-source et auto-h\xe9berg\xe9e8787 Vous pouvez l\u2019utiliser sur votre serveur. docker compose up -d Obtenez un bureau complet d\'IA : Claude, GPT, Gemini et n\'importe quel mod\xe8le compatible OpenAI, sortie en flux, appel \xe0 outils multiples, Python bac \xe0 sable, base de connaissances RAG, Deep Research, espace de travail d\'\xe9quipe, g\xe9n\xe9ration d\'images et console d\'administration compl\xe8te.","sidebar":"tutorialSidebar"}}}}')}}]);